// The curation layer for the asset library (2026-07-24). Kept OUT of
// manifest.json deliberately: that file is generated by scripts/vendor-*.mjs and
// describes only mechanical facts about published bytes (hash, size, licence,
// URL). Which category a model belongs to and what a kid might call it are
// editorial judgements — they belong in a reviewed, typed, hand-maintained file
// that a pipeline re-run can never silently overwrite.
//
// This replaces the hand-maintained GENRES[].models arrays that used to live in
// model-select.ts. Membership now travels with the asset, so adding a model can
// no longer desync from the selection layer (CLAUDE.md §4 — Open/Closed: extend
// config, don't edit call sites). asset-taxonomy.test.ts pins the migration.
//
// `tags` are synonyms the NAME does not already cover — matching always checks
// the name too, so self-evident models (apple, banana) legitimately carry few.
// Tags are selection/search metadata ONLY and are never rendered into the
// prompt, which keeps catalog tokens independent of how richly we tag.

/** Genre buckets. Each renders as one category heading in the prompt catalog
 *  (prompt-catalog.ts) and pairs with a trigger regex in model-select.ts. */
export const GENRE_IDS = [
  "people", "racing", "platformer", "space", "animals",
  "castle", "city", "nature", "water", "food",
] as const;
export type GenreId = (typeof GENRE_IDS)[number];

/** Models built on a shared skeleton, so they carry an identical set of named
 *  animation clips. This is a TECHNICAL fact, deliberately not a genre: the
 *  `people` genre also contains `grandstand`, and telling the model a stadium
 *  has a "walk" clip is exactly the kind of confident-but-wrong instruction
 *  that produces a broken game. Only a rig may drive the shared-clips prompt
 *  line. */
export const RIG_IDS = ["kenney_blocky"] as const;
export type RigId = (typeof RIG_IDS)[number];

export interface TaxonomyEntry {
  /** At least one — an ungrouped model is unreachable in the catalog. */
  genres: GenreId[];
  /** Extra words a kid might say. May be empty when the name says it all. */
  tags: string[];
  /** Set only when the model shares a skeleton (and therefore a clip list)
   *  with others. Absent for one-off meshes. */
  rig?: RigId;
}

const TAG_RE = /^[a-z0-9_]{1,32}$/;

