export function genresOf(name: string): readonly GenreId[] {
  return TAXONOMY[name]?.genres ?? [];
}

export function tagsOf(name: string): readonly string[] {
  return TAXONOMY[name]?.tags ?? [];
}

/** Members of a genre, filtered to what the manifest actually carries — so a
 *  curation entry for an asset we later drop can never name a dead model. */
export function modelsInGenre(genre: GenreId, available: ReadonlySet<string>): string[] {
  return Object.keys(TAXONOMY).filter((n) => available.has(n) && TAXONOMY[n]!.genres.includes(genre));
}

/** Models sharing a skeleton, filtered to what the manifest carries. This — not
 *  the `people` genre — is what may drive the shared-animation-clips prompt
 *  line, so scenery that merely sits in a people-ish genre (grandstand) can
 *  never be described to the model as having a walk cycle. */
export function modelsWithRig(rig: RigId, available: ReadonlySet<string>): string[] {
  return Object.keys(TAXONOMY).filter((n) => available.has(n) && TAXONOMY[n]!.rig === rig);
}

/**
 * Fails closed on malformed or incomplete curation. Called by the test suite
 * against the real manifest, so a model added without a taxonomy entry breaks
 * the build rather than quietly disappearing from every category heading.
 */
export function validateTaxonomy(
  modelNames: readonly string[],
  taxonomy: Record<string, TaxonomyEntry> = TAXONOMY,
): void {
  for (const name of modelNames) {
    const entry = taxonomy[name];
    if (!entry) throw new Error(`no taxonomy entry for model "${name}" — every model needs a genre and tags`);
    if (entry.genres.length === 0) throw new Error(`"${name}" has no genre — it would be unreachable in the catalog`);
    for (const genre of entry.genres) {
      if (!(GENRE_IDS as readonly string[]).includes(genre)) {
        throw new Error(`unknown genre "${genre}" on "${name}" — must be one of ${GENRE_IDS.join(", ")}`);
      }
    }
    const seen = new Set<string>();
    for (const tag of entry.tags) {
      if (!TAG_RE.test(tag)) throw new Error(`tag must match ${TAG_RE} on "${name}": "${tag}"`);
      if (seen.has(tag)) throw new Error(`duplicate tag "${tag}" on "${name}"`);
      seen.add(tag);
    }
  }
}
